var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"그로니아 국경지대 \\n관리국 관할 샤레이드 입국 관리소 주변, 대기 난민 거주구역.","ENG":"[[","TWN":"格羅尼亞邊境地區\\n管理局管轄的查雷德出入境管理所附近，難民等待居住區。","THA":"ชายแดนโกรเนีย\\nค่อยพักรอสำหรับผู้ลี้ภัยใกล้ศูนย์อพยพเมืองชาเรดขององค์การบริหารโลก","VTN":"Biên giới quốc gia Gronia\\nTrại tị nạn chờ nhập cư gần trung tâm nhập cư Charade của Cục Quản Lý.","SCN":"格洛尼亚边境地区\\n管理局管辖的查雷德出入境管理所附近，难民等待居住区。","DEU":"Gronia-Grenzgebiet.\\nUmgebung der Charade-Grenzverwaltung im Zuständigkeitsbereich der Administration, Wohngebiet der wartenden Flüchtlinge.","FRA":"Zone frontalière de Gronia\\nCamp de réfugiés en attente, aux alentours du bureau de l'immigration de Charade."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"네? 1년…… 이요?","JPN":"はい？　1年……ですか？","ENG":"Sorry? A... year?","TWN":"什麼？1年……嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_F","text":{"KOREA":"입국 심사는 그보다 오래 걸리는 경우가 보통입니다.","JPN":"入国審査はそれ以上長くかかるのが普通です。","ENG":"The immigration screening process usually takes longer than that.","TWN":"入境審查本來就需要比較長的時間。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_ADMIN_PATH_F","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_F","text":{"KOREA":"침식 증후군 검사나, 난민 신청에 필요한 행정 절차도 그렇고…….","JPN":"侵食症候群検査や、難民申請に必要な行政手続もそうですし……","ENG":"You have to get tested for Corruption Syndrome, and you also have to get all the documents you need for the refugee visa.","TWN":"侵蝕症候群檢驗，或是難民申請要走的行政程序也是一樣……"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_ADMIN_PATH_F","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_F","text":{"KOREA":"여길 넘어가려는 난민들은 수도 없이 많으니까요.","JPN":"ここを越えようとする難民は数え切れないほど多いですからね。","ENG":"Countless refugees come here to cross the border.","TWN":"畢竟有數不清的難民都等著要穿越國界。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_ADMIN_PATH_F","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"다른 방법은…… 없는 걸까요?","JPN":"他の方法は……ありませんか？","ENG":"Isn't there any other way?","TWN":"沒有……其他方法嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"신분증이나 과거 활동을 증명하는 경력서가 있으면 좀 더 단축될 수는 있다고 알고 있네만.","JPN":"身分証明書や過去の活動を証明する経歴書があれば、もう少し短縮できると聞いたんじゃが。","ENG":"If you have an identification card or something else that can prove your past history, then you may be able to shorten your waiting period.","TWN":"我聽說只要有身分證，或是可以證明過去活動的履歷，就可以縮短申請時間。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"자네, 신분증은 가지고 있나?","JPN":"君、身分証明書は持っているかね。","ENG":"Do you have an identification card?","TWN":"你有身分證嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아.","JPN":"あっ。","ENG":"Ah.","TWN":"嗯…"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"……아뇨.","JPN":"……いいえ。","ENG":"… No.","TWN":"……我沒有。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"목숨을 걸고 여기까지 오더라도, 진짜 남은 문제는 심사장의 까다로운 입국 절차라네.","JPN":"命がけでここまで来ても、真の問題は審査施設の厳しい入国手続きじゃ。","ENG":"Even if you make it all the way here alive, the real problem remains and it's the complicated immigration process.","TWN":"好不容易拚了命來到這裡，結果最大的難題卻是繁瑣的入境申請。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"수가 많은데다 이상한 사상에 물든 자들이 넘어갈 수도 있으니, 이해가 안 되는 건 아니지.","JPN":"数が多いうえに、変な思想に染まった者が入国することもあり得るから、理解できないことはない。","ENG":"It's understandable, given the number of people who want to cross the border, and some of them can be too dangerous to be let in.","TWN":"這個世界就是少數服從多數，即使是不合理的事，但世界就是這麼運作的。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"유감이지만, 우리로선 선택의 여지가 없다네.","JPN":"残念じゃが、ワシらとしては選択の余地がないんじゃ。","ENG":"It's a shame, but we have no choice.","TWN":"雖然很遺憾，但我們沒有選擇的餘地。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"그래도 이곳 거주구역은 정부군의 직접적인 보호를 받고 있어서 비교적 안전한 편이야.","JPN":"じゃが、ここの居住区域は政府軍から直接保護されているし、比較的安全なほうじゃ。","ENG":"At least this camp is under the direct protection of the government. It's fairly safe.","TWN":"不過這裡的住宅區是直接受到政府軍的保護，起碼安全一點囉。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"알겠습니다. 여기까지 태워주셔서 감사해요.","JPN":"わかりました。ここまで乗せてくださって、ありがとうございました。","ENG":"I see. Thank you for giving me a ride.","TWN":"好的，謝謝您載我到這裡。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"당연히 내가 더 고맙지. 그때 거기서 카운터를 만나게 될 줄 누가 알았겠나.","JPN":"いやいや、ワシのほうこそ感謝しとるよ。あの時、まさかカウンターに会えるなんて思ってなかったからのう。","ENG":"No, thank you. Who knew I'd be saved by a Counter like that?","TWN":"我才應該謝謝你呢！沒想到竟然會在那個時候遇到制裁者。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};